  ('social-worker-moex-05121', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '家庭暴力相關理論眾多。若社會工作者認為「家庭暴力的發生主要原因在於男性在社會化過程 中，被教導以先天生理上的優勢及社會文化賦予的資源來征服及控制女性」，則該位社會工作者 偏向以下列那個理論來解讀家庭暴力的發生？', '["社會學習理論", "女性主義觀點", "依附理論", "系統理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05122', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社區組織之敘述，下列何者錯誤？', '["地方發展模式認為社區居民是問題解決過程中的參與者", "社會計畫模式的主要目標在於解決實質的社區問題", "社會計畫模式認為社區居民扮演消費者或受益人的角色", "社會行動模式主要目標偏向以完成自助、社區能量整合之過程目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05123', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作理論運用發展的脈絡，如以發展時間序列為指標，下列敘述何者正確？', '["認知行為理論→精神分析理論→人本主義觀點→危機介入模型", "人本主義觀點→認知行為理論→危機介入模型→任務中心模型", "精神分析觀點→認知行為理論→心理暨社會學派→人本主義觀點", "精神分析觀點→危機介入模型→認知行為理論→人本主義觀點"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05124', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作倫理的觀點中主張：「倫理標準是基於文化、政治環境、當代的規範與道德標準，以 及其他外在環境等因素考量。所以倫理的考量無法斷言何種信仰或何人的信念優於他人」。請問 這是屬於何種倫理觀點？', '["目的論（teleological theories）", "相對論（relativism）", "直覺論（intuitionist）", "義務論（de-ontological theories）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05125', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作發展中，價值觀不斷地轉變。請問下列有關社會工作價值觀取向之描述，何者比較正確？', '["社會正義取向的價值觀認為資本主義的缺失和種族主義與其他形式的壓迫，產生受剝奪的低下 階層。因此，必須進行基本的社會改革", "臨床取向的價值觀著重於對實務工作者的保護", "父權主義取向的價值觀認為應該依賴政府或民間的財源幫助案主過有德性、完整且豐富的生活", "專業自我保衛取向的價值觀強調價值衝突與倫理兩難的議題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05126', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近年來大型災難頻傳，下列有關災難心理衛生觀念何者正確？①一定要受到災難的人才會受到影', '["大部分的人在災難後不認為自己需要心理衛生的服務，也不會尋求此方面的協助", "災難 心理衛生的協助偏向心理層面，而非實際面", "心理衛生工作人員為了順利介入災難事件的處 理，應該使用心理衛生標籤方式介入  ⑤心理衛生工作人員為了順利介入災難事件的處理，應該 擱置傳統方法，採取積極主動的接觸方式  ⑥介入方式必須適合災難的不同階段", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05127', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者於1869年成立，並展開濟貧與資源整合的工作？', '["瑪莉（Mary）館", "雷根（Regan）館", "湯恩比（Toynbee）館", "慈善組織會社（Charity Organization Society）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05128', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '評估夫妻或家庭的溝通方式時，必須能夠觀察到非語言的行為，舉例來說，家庭成員對望次數、 注意力的轉移情形、變換姿勢、手勢、聲調等。請問下列案例，先生為那種型態的婚姻溝通方式？ 太太說：對你來說，朋友與工作永遠是最重要的，你卻從來沒有花時間與孩子在一起。 先生說：我有花時間跟小孩子在一起啊！只是你從來都沒注意到。 太太說：你花了一些非常寶貴的且非常少的時間陪孩子，然後迫不及待的回到工作上或朋友一通 電話就出去。 先生說：這星期我已經花了好幾天陪孩子做功課……', '["防衛型", "退縮逃避型", "指責型", "迂迴型"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05129', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關「充權」理論的敘述，何者錯誤？', '["充權在社會工作領域中，代表的是協助案主在其生活歷程中獲得力量與權力", "充權的引導原則中，其中一種方式便是將重點放在檢視案主的優勢方面", "充權主要的焦點只在於消除壓迫案主之環境因素，而非案主個人能力的提升", "在充權的過程中，案主必須先相信自己有能力為自己做某些事情，而後才能為自己的生活及生 活以外的事件，增加主導與控制權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
